import { useState, memo } from 'react';
import Link from 'next/link';
import { ChevronRight, Minus, Plus } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import type { NavCategory } from './navbar.types';
import { useGlobal } from '@/context/GlobalContext';

interface MobileMenuCategoryProps {
    category: NavCategory;
    onClose: () => void;
}

export const MobileMenuCategory = memo(function MobileMenuCategory({ category, onClose }: MobileMenuCategoryProps) {
    const [isOpen, setIsOpen] = useState(false);
    const { t } = useGlobal();

    return (
        <div className="border-b border-white/5 last:border-0">
            {/* Category header */}
            <button
                className="flex items-center justify-between w-full py-5 text-left group transition-all"
                onClick={() => setIsOpen(!isOpen)}
                aria-expanded={isOpen}
            >
                <div className="flex flex-col">
                    <span
                        className={`text-[19px] font-medium tracking-wide transition-all duration-300 font-playfair ${isOpen ? 'text-[#C9A96E] translate-x-1' : 'text-white/80 group-hover:text-white'}`}
                        data-lang-key={category.dataKey}
                    >
                        {(category.dataKey ? t(category.dataKey) : '') || category.label}
                    </span>
                </div>

                <div className={`w-8 h-8 rounded-full flex items-center justify-center transition-all duration-500 ${isOpen ? 'bg-[#C9A96E] text-black rotate-180' : 'bg-white/5 text-white/20'}`}>
                    {isOpen ? <Minus size={16} /> : <Plus size={16} />}
                </div>
            </button>

            {/* Accordion sub-items */}
            <AnimatePresence initial={false}>
                {isOpen && (
                    <motion.div
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: 'auto', opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        transition={{ duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
                        style={{ overflow: 'hidden' }}
                    >
                        <div className="pb-8 space-y-6 pt-2">
                            {/* Detailed sub-categories */}
                            {category.subCategories.map((section, sIdx) => (
                                <div key={sIdx} className="space-y-3">
                                    <span className="block px-4 text-[10px] uppercase tracking-[0.25em] text-[#C9A96E]/60 font-bold border-l-2 border-[#C9A96E]/20 ml-1">
                                        {(section.dataKey ? t(section.dataKey) : '') || section.title}
                                    </span>
                                    <div className="space-y-1">
                                        {section.items.map((item) => (
                                            <Link
                                                key={item.href}
                                                href={item.href}
                                                onClick={onClose}
                                                className="flex items-center justify-between py-3 px-5 rounded-xl hover:bg-white/[0.03] transition-all text-[15px] text-white/50 hover:text-white group/item"
                                            >
                                                <span data-lang-key={item.dataKey} className="group-hover/item:translate-x-1 transition-transform duration-300">{(item.dataKey ? t(item.dataKey) : '') || item.label}</span>
                                                <ChevronRight size={14} className="text-white/10 group-hover/item:text-[#C9A96E] group-hover/item:translate-x-0 opacity-0 group-hover/item:opacity-100 transition-all" />
                                            </Link>
                                        ))}
                                    </div>
                                </div>
                            ))}

                            {/* View all link - Premium Button */}
                            <div className="px-4 pt-2">
                                <Link
                                    href={category.href}
                                    onClick={onClose}
                                    className="flex items-center justify-center gap-2 py-4 px-6 text-[13px] font-bold rounded-2xl bg-white/5 text-[#C9A96E] border border-[#C9A96E]/10 hover:bg-[#C9A96E]/10 hover:border-[#C9A96E]/30 transition-all active:scale-95"
                                >
                                    <span data-lang-key="common_view_all_arrow">{t('common_view_all_arrow') || 'Tüm Koleksiyonu Gör'}</span>
                                    <ChevronRight size={14} />
                                </Link>
                            </div>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
});
