import { useEffect, useRef, memo, useState } from 'react';
import Link from 'next/link';
import { X, Search, Heart, ShoppingBag, Instagram, Facebook, Twitter, Phone, Mail, MapPin, User, ChevronRight, Sparkles } from 'lucide-react';
import { motion, AnimatePresence, type Variants } from 'framer-motion';
import { MobileMenuCategory } from './MobileMenuCategory';
import { NavbarLogo } from './NavbarLogo';
import { LanguageSwitcher } from './LanguageSwitcher';
import { CurrencySwitcher } from './CurrencySwitcher';
import type { NavCategory } from './navbar.types';
import { useFavorites } from '@/hooks/useFavorites';
import { useCart } from '@/hooks/useCart';
import { useAuthStore } from '@/store/authStore';
import { useGlobal } from '@/context/GlobalContext';

interface MobileMenuProps {
    isOpen: boolean;
    onClose: () => void;
    categories: NavCategory[];
}

export const MobileMenu = memo(function MobileMenu({ isOpen, onClose, categories }: MobileMenuProps) {
    const { totalItems: itemCount, openCart } = useCart();
    const favCount = useFavorites((state) => state.favorites.length);
    const { user } = useAuthStore();
    const { t } = useGlobal();
    const overlayRef = useRef<HTMLDivElement>(null);
    const [searchValue, setSearchValue] = useState('');

    // Body scroll lock
    useEffect(() => {
        if (isOpen) {
            document.body.style.overflow = 'hidden';
        } else {
            document.body.style.overflow = '';
        }
        return () => { document.body.style.overflow = ''; };
    }, [isOpen]);

    // Escape key close
    useEffect(() => {
        const onKey = (e: KeyboardEvent) => { if (e.key === 'Escape' && isOpen) onClose(); };
        document.addEventListener('keydown', onKey);
        return () => document.removeEventListener('keydown', onKey);
    }, [isOpen, onClose]);

    // Swipe-to-close (left swipe ≥60px)
    useEffect(() => {
        const el = overlayRef.current;
        if (!el) return;
        let startX = 0;
        const onTouchStart = (e: TouchEvent) => { startX = e.touches[0].clientX; };
        const onTouchEnd = (e: TouchEvent) => {
            const dx = e.changedTouches[0].clientX - startX;
            if (dx < -60) onClose(); // swipe left to close
        };
        el.addEventListener('touchstart', onTouchStart, { passive: true });
        el.addEventListener('touchend', onTouchEnd, { passive: true });
        return () => {
            el.removeEventListener('touchstart', onTouchStart);
            el.removeEventListener('touchend', onTouchEnd);
        };
    }, [onClose]);

    const containerVariants = {
        hidden: { opacity: 0 },
        show: {
            opacity: 1,
            transition: { staggerChildren: 0.08, delayChildren: 0.3 },
        },
    };

    const itemVariants: Variants = {
        hidden: { opacity: 0, x: -30, filter: 'blur(10px)' },
        show: { opacity: 1, x: 0, filter: 'blur(0px)', transition: { duration: 0.6, ease: [0.22, 1, 0.36, 1] as [number, number, number, number] } },
    };

    return (
        <AnimatePresence mode="wait">
            {isOpen && (
                <>
                    {/* Backdrop */}
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="fixed inset-0 z-[9998] bg-black/80 backdrop-blur-md lg:hidden"
                        onClick={onClose}
                    />

                    {/* Drawer */}
                    <motion.div
                        ref={overlayRef}
                        initial={{ x: '-100%' }}
                        animate={{ x: 0 }}
                        exit={{ x: '-100%' }}
                        transition={{ duration: 0.6, ease: [0.32, 0.72, 0, 1] }}
                        className="fixed inset-y-0 left-0 z-[9999] w-[88%] max-w-[380px] lg:hidden flex flex-col shadow-[20px_0_50px_rgba(0,0,0,0.5)] border-r border-white/10"
                        style={{
                            background: 'linear-gradient(135deg, rgba(15, 15, 16, 0.98), rgba(28, 28, 30, 0.95))',
                            backdropFilter: 'blur(40px)',
                        }}
                        aria-label="Mobil navigasyon"
                        aria-modal="true"
                        role="dialog"
                    >
                        {/* Decorative Gradient Blob */}
                        <div className="absolute top-[-100px] left-[-100px] w-[300px] h-[300px] bg-[#C9A96E]/5 rounded-full blur-[100px] pointer-events-none" />

                        {/* Header */}
                        <div className="relative z-10 flex items-center justify-between px-6 py-6 border-b border-white/5 bg-white/[0.02]">
                            <NavbarLogo isScrolled={false} isMobileMenuOpen={true} />
                            <button
                                onClick={onClose}
                                className="flex items-center justify-center w-10 h-10 rounded-full bg-white/5 border border-white/10 text-white/50 hover:text-white transition-all active:scale-95 group"
                                aria-label="Menüyü kapat"
                            >
                                <X size={20} className="group-hover:rotate-90 transition-transform duration-300" />
                            </button>
                        </div>

                        {/* Search Bar - Premium Style */}
                        <div className="relative z-10 px-6 py-5">
                            <div className="relative group">
                                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-white/20 group-focus-within:text-[#C9A96E] transition-colors" size={16} />
                                <input
                                    id="mobile-search"
                                    name="q"
                                    type="text"
                                    autoComplete="off"
                                    value={searchValue}
                                    onChange={(e) => setSearchValue(e.target.value)}
                                    placeholder={t('common_search_placeholder') || 'Koleksiyonlarda ara...'}
                                    className="w-full pl-11 pr-4 py-3.5 bg-white/[0.03] border border-white/10 rounded-2xl text-white text-sm focus:outline-none focus:border-[#C9A96E]/40 focus:bg-white/[0.06] transition-all placeholder:text-white/20"
                                />
                            </div>
                        </div>

                        {/* Main Content Areas */}
                        <div className="flex-1 overflow-y-auto overflow-x-hidden custom-scrollbar px-6 pb-12">
                            <motion.div
                                variants={containerVariants}
                                initial="hidden"
                                animate="show"
                                className="flex flex-col min-h-full"
                            >
                                {/* Primary Navigation Categories */}
                                <div className="py-2 space-y-1">
                                    {categories.map((cat) => (
                                        <motion.div key={cat.id} variants={itemVariants}>
                                            <MobileMenuCategory category={cat} onClose={onClose} />
                                        </motion.div>
                                    ))}
                                </div>

                                {/* Secondary Links - Heritage Section */}
                                <motion.div variants={itemVariants} className="mt-10 pt-8 border-t border-white/5">
                                    <span className="block px-1 text-[11px] uppercase tracking-[0.3em] text-[#C9A96E] font-bold mb-6 font-playfair italic">
                                        {t('nav_heritage') || 'MİRASIMIZ & HİZMETLER'}
                                    </span>
                                    <div className="space-y-6">
                                        {[
                                            { label: 'Koleksiyonlar', href: '/koleksiyonlar', icon: Sparkles },
                                            { label: 'Lookbook', href: '/lookbook', icon: Heart },
                                            { label: 'Mağazalarımız', href: '/magazalar', icon: MapPin },
                                            { label: 'Biz Kimiz?', href: '/hakkimizda', icon: User },
                                        ].map((link) => (
                                            <Link
                                                key={link.href}
                                                href={link.href}
                                                onClick={onClose}
                                                className="flex items-center justify-between text-[16px] text-white/70 hover:text-white group px-1 transition-colors"
                                            >
                                                <div className="flex items-center gap-4">
                                                    <div className="w-8 h-8 rounded-lg bg-white/[0.03] border border-white/5 flex items-center justify-center group-hover:border-[#C9A96E]/30 group-hover:bg-[#C9A96E]/5 transition-all">
                                                        <link.icon size={16} className="text-white/30 group-hover:text-[#C9A96E] transition-colors" />
                                                    </div>
                                                    <span className="font-medium tracking-wide">{t(link.label.toLowerCase().replace(' ', '_')) || link.label}</span>
                                                </div>
                                                <ChevronRight size={14} className="text-white/20 group-hover:text-[#C9A96E] transition-all" />
                                            </Link>
                                        ))}
                                    </div>
                                </motion.div>

                                {/* Contact & Support - Concierge Style */}
                                <motion.div variants={itemVariants} className="mt-10 pt-8 border-t border-white/5">
                                    <span className="block px-1 text-[11px] uppercase tracking-[0.3em] text-[#C9A96E] font-bold mb-6 font-playfair italic">
                                        {t('nav_concierge') || 'CONCIERGE'}
                                    </span>
                                    <div className="space-y-5 mb-10">
                                        <a href="tel:+902125555555" className="flex items-center gap-4 text-white/50 hover:text-white transition-colors text-sm group">
                                            <div className="w-10 h-10 rounded-full bg-white/[0.03] border border-white/5 flex items-center justify-center group-hover:bg-[#C9A96E]/10 group-hover:border-[#C9A96E]/30 transition-all">
                                                <Phone size={14} className="group-hover:text-[#C9A96E]" />
                                            </div>
                                            <div className="flex flex-col">
                                                <span className="text-[10px] uppercase tracking-widest text-white/20">{t('common_phone') || 'Telefon'}</span>
                                                <span className="font-medium">+90 (212) 555 55 55</span>
                                            </div>
                                        </a>
                                        <a href="mailto:info@selishome.com" className="flex items-center gap-4 text-white/50 hover:text-white transition-colors text-sm group">
                                            <div className="w-10 h-10 rounded-full bg-white/[0.03] border border-white/5 flex items-center justify-center group-hover:bg-[#C9A96E]/10 group-hover:border-[#C9A96E]/30 transition-all">
                                                <Mail size={14} className="group-hover:text-[#C9A96E]" />
                                            </div>
                                            <div className="flex flex-col">
                                                <span className="text-[10px] uppercase tracking-widest text-white/20">{t('common_email') || 'E-posta'}</span>
                                                <span className="font-medium">info@selishome.com</span>
                                            </div>
                                        </a>
                                    </div>
                                </motion.div>

                                {/* Social Icons - Premium Circles */}
                                <motion.div variants={itemVariants} className="flex gap-4 pb-16">
                                    {[
                                        { icon: Instagram, href: '#' },
                                        { icon: Facebook, href: '#' },
                                        { icon: Twitter, href: '#' }
                                    ].map((social, i) => (
                                        <a
                                            key={i}
                                            href={social.href}
                                            className="w-12 h-12 rounded-full bg-white/[0.03] border border-white/5 flex items-center justify-center text-white/30 hover:bg-[#C9A96E] hover:text-black hover:border-[#C9A96E] transition-all duration-500"
                                        >
                                            <social.icon size={20} />
                                        </a>
                                    ))}
                                </motion.div>
                            </motion.div>
                        </div>

                        {/* Sticky Footer Actions - Glassy & Premium */}
                        <div className="relative z-10 px-6 py-8 border-t border-white/10 bg-black/40 backdrop-blur-3xl">
                            <div className="flex gap-4">
                                <Link
                                    href="/hesabim"
                                    onClick={onClose}
                                    className="flex-[2] flex items-center justify-center gap-3 h-14 rounded-2xl bg-white text-black font-bold text-sm hover:bg-[#F5F0EB] transition-all hover:scale-[1.02] active:scale-95 shadow-xl"
                                >
                                    <User size={18} />
                                    <span className="tracking-tight">{user ? (t('nav_account') || 'Hesabım') : (t('nav_login') || 'Giriş Yap')}</span>
                                </Link>
                                <button
                                    onClick={() => { onClose(); openCart(); }}
                                    className="flex-1 relative flex items-center justify-center h-14 rounded-2xl bg-[#C9A96E] text-black hover:bg-[#B8985D] transition-all hover:scale-[1.02] active:scale-95 shadow-xl shadow-[#C9A96E]/10"
                                >
                                    <ShoppingBag size={22} />
                                    {itemCount > 0 && (
                                        <span className="absolute -top-1.5 -right-1.5 min-w-[22px] h-[22px] bg-white text-black text-[11px] font-black rounded-full flex items-center justify-center border-2 border-black shadow-lg">
                                            {itemCount}
                                        </span>
                                    )}
                                </button>
                            </div>

                            <div className="flex items-center justify-center gap-6 mt-8">
                                <LanguageSwitcher isScrolled={false} />
                                <div className="w-px h-4 bg-white/10" />
                                <CurrencySwitcher isScrolled={false} />
                            </div>
                        </div>
                    </motion.div>
                </>
            )}
        </AnimatePresence>
    );
});
