'use client';

import * as React from 'react';
import Link from 'next/link';
import { Menu, Search, X, Heart, User, ShoppingBag, MapPin, Sparkles } from 'lucide-react';

import { useNavbarScroll } from './useNavbarScroll';
import { NavbarLogo } from './NavbarLogo';
import { NavbarDesktop } from './NavbarDesktop';
import { SearchBar } from './SearchBar';
import { LanguageSwitcher } from './LanguageSwitcher';
import { CurrencySwitcher } from './CurrencySwitcher';
import { MobileMenu } from './MobileMenu';
import { NAV_CATEGORIES } from './navData';
import { useGlobal } from '@/context/GlobalContext';
import { usePathname } from 'next/navigation';
import { useDarkMode } from '@/hooks/useDarkMode';
import { useCart } from '@/hooks/useCart';
import { Moon, Sun } from 'lucide-react';
import { supabase } from '@/lib/supabase';
import type { NavCategory } from './navbar.types';
import { useHeaderMenu } from './useHeaderMenu';
// Cache bust: 1

export function Navbar() {
    const pathname = usePathname();
    const isProductPage = pathname?.startsWith('/urun/');

    const [activeCategoryId, setActiveCategoryId] = React.useState<string | null>(null);
    const [isSearchOpen, setIsSearchOpen] = React.useState(false);
    const [isMobileOpen, setIsMobileOpen] = React.useState(false);
    const { dynamicCategories } = useHeaderMenu(NAV_CATEGORIES);
    const { openCart } = useCart();
    const hoverTimerRef = React.useRef<ReturnType<typeof setTimeout> | null>(null);

    const { isScrolled: _isScrolled } = useNavbarScroll(activeCategoryId !== null);

    // Override isScrolled to false on the PDP so the big logo always stays.
    const isScrolled = isProductPage ? false : _isScrolled;

    const { t, currency } = useGlobal();

    const handleCategoryEnter = React.useCallback((id: string) => {
        if (isSearchOpen) return;
        if (hoverTimerRef.current) clearTimeout(hoverTimerRef.current);
        hoverTimerRef.current = setTimeout(() => setActiveCategoryId(id), 150);
    }, [isSearchOpen]);

    const handleCategoryLeave = React.useCallback(() => {
        if (hoverTimerRef.current) clearTimeout(hoverTimerRef.current);
        hoverTimerRef.current = setTimeout(() => setActiveCategoryId(null), 150);
    }, []);

    const handleMegaMenuEnter = React.useCallback(() => {
        if (hoverTimerRef.current) clearTimeout(hoverTimerRef.current);
    }, []);

    const handleMegaMenuClose = React.useCallback(() => setActiveCategoryId(null), []);
    const handleMobileOpen = React.useCallback(() => setIsMobileOpen(true), []);
    const handleMobileClose = React.useCallback(() => setIsMobileOpen(false), []);
    const handleSearchOpen = React.useCallback(() => { setActiveCategoryId(null); setIsSearchOpen(true); }, []);
    const handleSearchClose = React.useCallback(() => setIsSearchOpen(false), []);

    const { isDark, toggle: toggleDarkMode, mounted: darkModeMounted } = useDarkMode();

    const goldColor = '#C9A96E';

    // Removed 3D Tilt stuff for stability


    // Material definitions - "Heritage Modern" Style
    const heritageMaterial = "bg-[#FCFBF7]/95 dark:bg-black backdrop-blur-md border border-[#E5D5BC]/30 dark:border-white/20 shadow-[0_10px_40px_rgba(0,0,0,0.05)]";
    const goldAccent = "text-[#C9A96E]";

    const isHome = pathname === '/' || pathname === '/tr' || pathname === '/en' || pathname === '/de' || pathname === '/fr' || pathname === '/ar';

    return (
        <header className={`${isHome ? 'fixed' : 'sticky'} top-0 left-0 right-0 z-[100] flex flex-col items-center transition-all duration-500 pointer-events-none ${isScrolled ? 'pt-2' : 'pt-4 md:pt-8'}`}>
            {/* Top Logo - centered and prominent */}
            <div className={`pointer-events-auto transition-all duration-500 transform hover:scale-105 ${isScrolled ? 'mb-1' : 'mb-3 md:mb-4'}`}>
                <NavbarLogo isScrolled={isScrolled} />
            </div>

            {/* Navigation Strip */}
            <nav className={`pointer-events-auto flex items-center justify-between px-4 md:px-10 py-2.5 md:py-3 rounded-full ${heritageMaterial} w-[94%] md:w-auto shadow-lg shadow-black/5`}>
                {/* Left: Cart & Lang (Simplified Tools) */}
                <div className="flex items-center gap-2 md:gap-4 min-w-0 md:min-w-[120px]">
                    <div className="hidden sm:block">
                        <LanguageSwitcher isScrolled={isScrolled} />
                    </div>
                    <button
                        onClick={() => openCart()}
                        className="p-2 hover:bg-black/5 dark:hover:bg-white/10 rounded-full transition-colors relative"
                    >
                        <ShoppingBag size={20} className="text-[#4A4A4A] dark:text-white" strokeWidth={1.5} />
                    </button>
                </div>

                {/* Center: Desktop Navigation */}
                <div className="hidden lg:block mx-8">
                    <NavbarDesktop
                        categories={dynamicCategories}
                        isScrolled={isScrolled}
                        activeCategoryId={activeCategoryId}
                        onCategoryEnter={handleCategoryEnter}
                        onCategoryLeave={handleCategoryLeave}
                        onMegaMenuEnter={handleMegaMenuEnter}
                        onMegaMenuClose={handleMegaMenuClose}
                    />
                </div>

                {/* Right: Tools (Search, User, DarkMode) */}
                <div className="flex items-center gap-2 md:gap-3 min-w-0 justify-end">
                    {/* Extra page links - desktop only */}
                    <div className="hidden lg:flex items-center gap-1">
                        <Link
                            href="/koleksiyonlar"
                            className="px-3 py-1.5 rounded-full text-[15px] italic transition-all duration-300 hover:bg-black/5 dark:hover:bg-white/10"
                            style={{ fontFamily: '"Cormorant Garamond", serif', fontWeight: 500, color: pathname === '/koleksiyonlar' ? '#C9A96E' : undefined }}
                        >
                            {t('nav_collections_page') || 'Koleksiyonlar'}
                        </Link>
                        <Link
                            href="/hakkimizda"
                            className="px-3 py-1.5 rounded-full text-[15px] italic transition-all duration-300 hover:bg-black/5 dark:hover:bg-white/10 dark:text-white"
                            style={{ fontFamily: '"Cormorant Garamond", serif', fontWeight: 500, color: pathname === '/hakkimizda' ? '#C9A96E' : undefined }}
                        >
                            {t('nav_about') || 'Hakkımızda'}
                        </Link>
                        <div className="w-px h-4 bg-[#E5D5BC]/60 dark:bg-white/20 mx-1" />
                    </div>
                    <SearchBar
                        isScrolled={isScrolled}
                        isOpen={isSearchOpen}
                        onOpen={handleSearchOpen}
                        onClose={handleSearchClose}
                    />

                    <Link href="/hesabim">
                        <div className="p-2 hover:bg-black/5 dark:hover:bg-white/10 rounded-full transition-colors">
                            <User size={20} className="text-[#4A4A4A] dark:text-white" strokeWidth={1.5} />
                        </div>
                    </Link>

                    {darkModeMounted && (
                        <button
                            onClick={toggleDarkMode}
                            className="p-2 hover:bg-black/5 dark:hover:bg-white/10 rounded-full transition-colors hidden sm:block"
                            aria-label="Karanlık Mod Değiştir"
                        >
                            {isDark ? <Sun size={20} className="text-[#C9A96E]" strokeWidth={1.5} /> : <Moon size={20} className="text-[#4A4A4A] dark:text-white" strokeWidth={1.5} />}
                        </button>
                    )}

                    {/* Mobile Menu Icon */}
                    <div className="lg:hidden ml-1">
                        <button onClick={handleMobileOpen} className="p-2 focus:outline-none">
                            <Menu size={24} className="text-[#4A4A4A] dark:text-white" />
                        </button>
                    </div>
                </div>
            </nav>

            {/* Mobile Menu */}
            <MobileMenu
                isOpen={isMobileOpen}
                onClose={handleMobileClose}
                categories={dynamicCategories}
            />

            {/* Accessibility Link - Absolute relative to header */}
            <a href="#main-content" className="sr-only focus:not-sr-only absolute top-4 left-4 z-[60] bg-white text-black p-2 rounded shadow-lg">
                {t('common_skip_to_content') || 'İçeriğe geç'}
            </a>
        </header>
    );
}
